enum HttpMethod{get,put,post,delete,propfind}class HttpRequestDescriptor{const HttpRequestDescriptor({required this.method,required this.url,required this.headers,this.body});final HttpMethod method;final Uri url;final Map<String,String> headers;final String? body;}class HttpResponseDescriptor{const HttpResponseDescriptor({required this.statusCode,required this.headers,required this.body});final int statusCode;final Map<String,String> headers;final String body;bool get isSuccess=>statusCode>=200&&statusCode<300;}
